import React from 'react';

const eventos = [
  {
    id: 1,
    titulo: '6TH FANMEETING «STAY in Our Little House»',
    periodo: '28 e 29 de março · 4 e 5 de abril de 2026',
    dataDestaque: '2026-03-28',
    horario: 'Sessões em horários divulgados pela bilheteria oficial',
    fuso: 'Coreia do Sul (KST, UTC+9)',
    local: 'Inspire Arena',
    cidade: 'Incheon',
    pais: 'Coreia do Sul',
    tipo: 'Fan Meeting',
    ingressos: 'Esgotado',
    descricao:
      'Sexto encontro oficial com fãs: conceito de “casa aconchegante”, com performances especiais, dinâmicas e histórias do grupo. As últimas sessões de cada fim de semana (29 de março e 5 de abril) também são transmitidas online na plataforma Beyond LIVE para quem comprou o acesso à live.',
    link: 'https://www.kotourlive.com/en/concerts/stray-kids-6th-fan-meeting-stay-in-our-little-house',
    linkLabel: 'Página do evento'
  },
  {
    id: 2,
    titulo: 'Beyond LIVE — encerramentos do fan meeting',
    periodo: '29 de março e 5 de abril de 2026',
    dataDestaque: '2026-03-29',
    horario: 'Conforme programação do fan meeting',
    fuso: 'Transmissão ao vivo (horário divulgado na compra)',
    local: 'Transmissão online',
    cidade: 'Beyond LIVE',
    pais: 'Online',
    tipo: 'Transmissão',
    ingressos: 'Via pacote Beyond LIVE',
    descricao:
      'Transmissão das últimas datas de cada fim de semana do fan meeting «STAY in Our Little House». Quem não está na arena pode acompanhar comprando o acesso digital na plataforma.',
    link: 'https://beyondlive.com',
    linkLabel: 'Beyond LIVE'
  },
  {
    id: 3,
    titulo: 'Governors Ball Music Festival 2026',
    periodo: '6 de junho de 2026',
    dataDestaque: '2026-06-06',
    horario: 'Conforme grade do festival (geralmente tarde/noite)',
    fuso: 'EUA — horário local de Nova York',
    local: 'Flushing Meadows Corona Park',
    cidade: 'Nova York',
    pais: 'Estados Unidos',
    tipo: 'Festival',
    ingressos: 'À venda',
    descricao:
      'Stray Kids está entre as atrações anunciadas do Governors Ball 2026. Festival ao ar livre com vários palcos; vale acompanhar o site oficial para lineup por dia e tipo de ingresso (dia único ou passe completo).',
    link: 'https://www.govball.com',
    linkLabel: 'Site do festival'
  },
  {
    id: 4,
    titulo: 'Rock in Rio 2026 — Stray Kids',
    periodo: '11 de setembro de 2026',
    dataDestaque: '2026-09-11',
    horario: 'A definir pela organização do festival',
    fuso: 'Brasil — horário de Brasília',
    local: 'Cidade do Rock',
    cidade: 'Rio de Janeiro',
    pais: 'Brasil',
    tipo: 'Festival',
    ingressos: 'Consultar site oficial',
    descricao:
      'Apresentação do grupo no Rock in Rio. Fique atento ao site e às redes oficiais do festival para vendas de ingressos, horário exato do show e possíveis pacotes ou meia-entrada.',
    link: 'https://rockinrio.com.br',
    linkLabel: 'Rock in Rio'
  },
  {
    id: 5,
    titulo: 'World Tour 2026 (turnê mundial)',
    periodo: 'Datas e cidades em anúncio oficial',
    dataDestaque: '2026-07-01',
    horario: '—',
    fuso: '—',
    local: 'Ásia, Américas, Europa e Oceania (previsto)',
    cidade: 'Várias',
    pais: '—',
    tipo: 'Turnê',
    ingressos: 'Em breve',
    descricao:
      'Nova turnê mundial foi confirmada em comunicados à imprensa; cidades e datas costumam ser divulgadas aos poucos pelo JYP Entertainment e pelos canais oficiais do Stray Kids. Vale seguir o Twitter/X, Instagram e o fan club para pré-vendas.',
    link: 'https://www.instagram.com/realstraykids/',
    linkLabel: 'Instagram oficial'
  }
];

function Agenda() {
  const getBadgeClass = (tipo) => {
    switch (tipo) {
      case 'Festival':
        return 'bg-primary';
      case 'Fan Meeting':
        return 'bg-success';
      case 'Transmissão':
        return 'bg-info text-dark';
      case 'Turnê':
        return 'bg-dark';
      case 'Mídia':
        return 'bg-secondary';
      default:
        return 'bg-secondary';
    }
  };

  const getIngressosBadge = (status) => {
    switch (status) {
      case 'À venda':
        return <span className="badge bg-success">À venda</span>;
      case 'Esgotado':
        return <span className="badge bg-danger">Esgotado</span>;
      case 'Em breve':
        return <span className="badge bg-warning text-dark">Em breve</span>;
      case 'Via pacote Beyond LIVE':
        return <span className="badge bg-info text-dark">Digital / Beyond LIVE</span>;
      case 'Consultar site oficial':
        return <span className="badge bg-primary">Ver site oficial</span>;
      default:
        return <span className="badge bg-secondary">N/A</span>;
    }
  };

  return (
    <div className="container py-5">
      <h1 className="mb-3" style={{ color: '#198754' }}>
        Agenda do Stray Kids
      </h1>
      <p className="lead text-muted mb-2">
        Próximos compromissos públicos divulgados na mídia e nos canais oficiais — fan meetings, festivais e
        turnê.
      </p>
      <p className="small text-secondary mb-5">
        Horários e vendas podem mudar; sempre confira o link de cada evento e as redes{' '}
        <a href="https://www.instagram.com/realstraykids/" target="_blank" rel="noopener noreferrer">
          @realstraykids
        </a>{' '}
        antes de comprar passagem ou ingresso.
      </p>

      <div className="row g-4">
        {eventos.map((evento) => {
          const d = new Date(evento.dataDestaque + 'T12:00:00');
          const dia = d.getDate();
          const mes = d.toLocaleDateString('pt-BR', { month: 'short' }).replace('.', '').toUpperCase();
          const ano = d.getFullYear();

          return (
            <div key={evento.id} className="col-12">
              <div className="card shadow-sm border-0" style={{ borderLeft: '4px solid #28a745' }}>
                <div className="card-body p-4">
                  <div className="row align-items-start">
                    <div className="col-lg-2 text-center mb-3 mb-lg-0">
                      <div
                        className="rounded-3 py-3 px-2 text-white mx-auto"
                        style={{ maxWidth: '100px', background: 'linear-gradient(145deg, #198754, #20c997)' }}
                      >
                        <div className="small opacity-75">{ano}</div>
                        <div className="display-6 fw-bold lh-1 my-1">{dia}</div>
                        <div className="small fw-semibold">{mes}</div>
                      </div>
                      <p className="small text-muted mt-2 mb-0 px-1">{evento.periodo}</p>
                    </div>

                    <div className="col-lg-7">
                      <div className="d-flex flex-wrap align-items-center gap-2 mb-2">
                        <span className={`badge ${getBadgeClass(evento.tipo)}`}>{evento.tipo}</span>
                        {getIngressosBadge(evento.ingressos)}
                      </div>
                      <h2 className="h4 mb-2">{evento.titulo}</h2>
                      <p className="text-muted small mb-3">{evento.descricao}</p>

                      <ul className="list-unstyled small mb-0">
                        <li className="mb-1">
                          <strong className="text-dark">Onde:</strong> {evento.local}, {evento.cidade}
                          {evento.pais && evento.pais !== '—' ? ` · ${evento.pais}` : ''}
                        </li>
                        <li className="mb-1">
                          <strong className="text-dark">Quando:</strong> {evento.periodo}
                        </li>
                        {evento.horario !== '—' && (
                          <li className="mb-1">
                            <strong className="text-dark">Horário:</strong> {evento.horario}
                          </li>
                        )}
                        <li>
                          <strong className="text-dark">Fuso / detalhe:</strong> {evento.fuso}
                        </li>
                      </ul>
                    </div>

                    <div className="col-lg-3 mt-3 mt-lg-0 text-lg-end d-grid d-lg-block">
                      {evento.link ? (
                        <a
                          href={evento.link}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="btn btn-success"
                        >
                          {evento.linkLabel} ↗
                        </a>
                      ) : null}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      <section className="mt-5">
        <div className="alert alert-light border shadow-sm">
          <strong className="text-success">Dica para STAYs:</strong> para shows no exterior, confira visto,
          seguro-viagem e se o ingresso inclui apenas o festival ou também setlist por dia. Fan meetings na Coreia
          costumam exigir cadastro em fan club e venda em sites como Interpark / plataformas indicadas pelo JYP.
        </div>
      </section>
    </div>
  );
}

export default Agenda;
